[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a cdi:StructuredDataSet ;
                    ns1:hasPhysicalMapping [ ns1:format "float64" ;
                            ns1:formats_InstanceVariable <https://example.org/var-pressure> ;
                            ns1:index 1 ;
                            ns1:locator "/pressure[*][*]" ;
                            ns1:physicalDataType "Numeric" ],
                        [ ns1:format "float64" ;
                            ns1:formats_InstanceVariable <https://example.org/var-temperature> ;
                            ns1:index 0 ;
                            ns1:locator "/temperature[*][*]" ;
                            ns1:physicalDataType "Numeric" ] ] ;
            sh:resultMessage "A StructuredDataSet should have physical mappings (cdif:hasPhysicalMapping) linking variables to their physical representation." ;
            sh:resultPath cdif:hasPhysicalMapping ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A StructuredDataSet should have physical mappings (cdif:hasPhysicalMapping) linking variables to their physical representation." ;
                    sh:minCount 1 ;
                    sh:path cdif:hasPhysicalMapping ;
                    sh:severity sh:Warning ] ] .

