@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix cdif: <https://cdif.org/0.1/> .
@prefix csvw: <http://www.w3.org/ns/csvw#> .
@prefix ns1: <cdif:> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a cdi:TabularTextDataSet,
                        schema1:Dataset ;
                    ns1:hasPhysicalMapping [ ns1:format "#,##0.00" ;
                            ns1:formats_InstanceVariable <https://example.org/var-temperature> ;
                            ns1:index 2 ;
                            ns1:physicalDataType "Numeric" ;
                            cdi:decimalPositions 2 ;
                            cdi:length 12 ;
                            cdi:scale 1 ],
                        [ ns1:format "YYYY-MM-DD" ;
                            ns1:formats_InstanceVariable <https://example.org/var-date> ;
                            ns1:index 1 ;
                            ns1:physicalDataType "Date" ;
                            cdi:nullSequence "NA" ],
                        [ ns1:formats_InstanceVariable <https://example.org/var-station-id> ;
                            ns1:index 0 ;
                            ns1:physicalDataType "String" ;
                            cdi:isRequired true ;
                            cdi:length 16 ] ;
                    cdi:arrayBase 1 ;
                    cdi:escapeCharacter "\"" ;
                    cdi:headerIsCaseSensitive false ;
                    cdi:isDelimited true ;
                    cdi:isFixedWidth false ;
                    cdi:treatConsecutiveDelimitersAsOne false ;
                    csvw:commentPrefix "#" ;
                    csvw:delimiter "," ;
                    csvw:header true ;
                    csvw:headerRowCount 1 ;
                    csvw:lineTerminators "CRLF" ;
                    csvw:quoteChar "\"" ;
                    csvw:skipBlankRows false ;
                    csvw:skipColumns 0 ;
                    csvw:skipInitialSpace true ;
                    csvw:skipRows 0 ;
                    csvw:tableDirection "Ltr" ;
                    csvw:textDirection "Inherit" ;
                    csvw:trim "true" ] ;
            sh:resultMessage "A TabularTextDataSet must have physical mappings (cdif:hasPhysicalMapping) linking variables to columns (required by the JSON Schema)." ;
            sh:resultPath cdif:hasPhysicalMapping ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A TabularTextDataSet must have physical mappings (cdif:hasPhysicalMapping) linking variables to columns (required by the JSON Schema)." ;
                    sh:minCount 1 ;
                    sh:path cdif:hasPhysicalMapping ;
                    sh:severity sh:Violation ] ] .

